    {
        "challenge_id": "macos-dock",
        "title": "macOS Dock Magnification",
        "category": "interactivity",
        "type": "dom_manipulation",
        "difficulty": "medium",
        "description": "Recreate the iconic macOS Dock magnification effect:\n1. When the mouse enters a dock icon, add class 'hovered' and scale it to 2x\n2. Its immediate neighbors get class 'neighbor' and scale to 1.4x\n3. On mouseout, remove all scaling classes\n4. All icons must have a smooth CSS transition\n\nUse transform-origin: bottom center so icons grow upward.",
        "starter_html": '<div class="dock">\n  <div class="dock-item">\U0001f5c2</div>\n  <div class="dock-item">\U0001f310</div>\n  <div class="dock-item">\U0001f4ac</div>\n  <div class="dock-item">\U0001f3b5</div>\n  <div class="dock-item">\u2328</div>\n</div>',
        "starter_css": "body {\n  display: flex;\n  justify-content: center;\n  align-items: flex-end;\n  min-height: 200px;\n  margin: 0;\n  background: linear-gradient(to bottom, #1a1a2e, #16213e);\n  padding-bottom: 20px;\n}\n.dock {\n  display: flex;\n  align-items: flex-end;\n  gap: 8px;\n  background: rgba(255,255,255,0.15);\n  backdrop-filter: blur(10px);\n  border-radius: 16px;\n  padding: 8px 12px;\n  border: 1px solid rgba(255,255,255,0.2);\n}\n.dock-item {\n  width: 60px;\n  height: 60px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 2rem;\n  border-radius: 12px;\n  cursor: pointer;\n  /* Add transition and transform-origin here */\n}\n/* Add .hovered and .neighbor rules here */",
        "starter_js": "const items = Array.from(document.querySelectorAll('.dock-item'));\n\nitems.forEach(function(item, i) {\n  item.addEventListener('mouseover', function() {\n    // 1. Remove all 'hovered' and 'neighbor' classes\n    // 2. Add 'hovered' to item\n    // 3. Add 'neighbor' to items[i-1] and items[i+1] if they exist\n  });\n  item.addEventListener('mouseout', function() {\n    // Remove all 'hovered' and 'neighbor' classes\n  });\n});",
        "solution_html": '<div class="dock">\n  <div class="dock-item">\U0001f5c2</div>\n  <div class="dock-item">\U0001f310</div>\n  <div class="dock-item">\U0001f4ac</div>\n  <div class="dock-item">\U0001f3b5</div>\n  <div class="dock-item">\u2328</div>\n</div>',
        "solution_css": "body { display:flex; justify-content:center; align-items:flex-end; min-height:200px; margin:0; background:linear-gradient(to bottom,#1a1a2e,#16213e); padding-bottom:20px; }\n.dock { display:flex; align-items:flex-end; gap:8px; background:rgba(255,255,255,0.15); backdrop-filter:blur(10px); border-radius:16px; padding:8px 12px; border:1px solid rgba(255,255,255,0.2); }\n.dock-item { width:60px; height:60px; display:flex; align-items:center; justify-content:center; font-size:2rem; border-radius:12px; cursor:pointer; transition:transform 0.2s ease; transform-origin:bottom center; }\n.dock-item.hovered { transform:scale(2); }\n.dock-item.neighbor { transform:scale(1.4); }",
        "solution_js": 'const items = Array.from(document.querySelectorAll(".dock-item"));\nitems.forEach(function(item, i) {\n  item.addEventListener("mouseover", function() {\n    items.forEach(function(el) { el.classList.remove("hovered", "neighbor"); });\n    item.classList.add("hovered");\n    if (items[i - 1]) items[i - 1].classList.add("neighbor");\n    if (items[i + 1]) items[i + 1].classList.add("neighbor");\n  });\n  item.addEventListener("mouseout", function() {\n    items.forEach(function(el) { el.classList.remove("hovered", "neighbor"); });\n  });\n});',
        "test_cases": json.dumps([
            {"type": "element_count", "selector": ".dock-item", "expected": 5, "description": "Has 5 dock items"},
            {"type": "has_style_nonzero", "selector": ".dock-item", "property": "transitionDuration", "description": "Dock items have a CSS transition"},
            {"type": "event_test", "selector": ".dock-item", "event": "mouseover", "then_check": {"type": "has_class", "selector": ".dock-item", "className": "hovered"}, "description": "Hovering adds 'hovered' class"},
            {"type": "event_test", "selector": ".dock-item", "event": "mouseout", "then_check": {"type": "not_has_class", "selector": ".dock-item", "className": "hovered"}, "description": "Mouseout removes 'hovered' class"},
        ]),
        "hints": json.dumps([
            "Use transform: scale(2) with transform-origin: bottom center so icons grow upward like the real Dock",
            "Store items as Array.from(...) so you can reference neighbors by index: items[i-1] and items[i+1]",
            "Add transition: transform 0.2s ease to .dock-item in CSS for smooth animation",
        ]),
    },
