    {
        "challenge_id": "command-palette",
        "title": "Command Palette (Cmd+K)",
        "category": "interactivity",
        "type": "dom_manipulation",
        "difficulty": "hard",
        "description": "Build a VS Code-style command palette:\n1. #palette starts with class 'hidden'\n2. Clicking #open-btn removes 'hidden' to reveal the palette\n3. Pressing Escape adds 'hidden' back to close it\n4. Typing in #palette-search filters .cmd-item elements — hide non-matching ones\n5. Commands: New File, Open Terminal, Git Commit, Format Document, Toggle Dark Mode",
        "starter_html": '<div class="app">\n  <h1>My Editor</h1>\n  <button id="open-btn">Open Command Palette</button>\n</div>\n\n<div id="palette" class="hidden">\n  <div class="palette-inner">\n    <input id="palette-search" placeholder="Type a command..." autocomplete="off" />\n    <ul id="cmd-list">\n      <li class="cmd-item">New File</li>\n      <li class="cmd-item">Open Terminal</li>\n      <li class="cmd-item">Git Commit</li>\n      <li class="cmd-item">Format Document</li>\n      <li class="cmd-item">Toggle Dark Mode</li>\n    </ul>\n  </div>\n</div>',
        "starter_css": "body { font-family:sans-serif; padding:2rem; background:#1e1e2e; color:white; }\n#open-btn { padding:0.5rem 1rem; background:#6c63ff; color:white; border:none; border-radius:6px; cursor:pointer; }\n#palette { position:fixed; inset:0; background:rgba(0,0,0,0.6); display:flex; align-items:flex-start; justify-content:center; padding-top:15vh; z-index:1000; }\n#palette.hidden { display:none; }\n.palette-inner { background:#2a2a3d; border-radius:12px; width:500px; overflow:hidden; box-shadow:0 20px 60px rgba(0,0,0,0.5); }\n#palette-search { width:100%; padding:16px 20px; background:transparent; border:none; border-bottom:1px solid #3a3a50; color:white; font-size:1rem; outline:none; box-sizing:border-box; }\n#cmd-list { list-style:none; padding:8px 0; margin:0; max-height:300px; overflow-y:auto; }\n.cmd-item { padding:10px 20px; cursor:pointer; color:#ccc; }\n.cmd-item:hover { background:#3a3a50; color:white; }",
        "starter_js": "// 1. Open palette when #open-btn is clicked\n// 2. Close palette when Escape is pressed (keydown on document)\n// 3. Filter .cmd-item elements based on #palette-search input\n",
        "solution_html": '<div class="app">\n  <h1>My Editor</h1>\n  <button id="open-btn">Open Command Palette</button>\n</div>\n\n<div id="palette" class="hidden">\n  <div class="palette-inner">\n    <input id="palette-search" placeholder="Type a command..." autocomplete="off" />\n    <ul id="cmd-list">\n      <li class="cmd-item">New File</li>\n      <li class="cmd-item">Open Terminal</li>\n      <li class="cmd-item">Git Commit</li>\n      <li class="cmd-item">Format Document</li>\n      <li class="cmd-item">Toggle Dark Mode</li>\n    </ul>\n  </div>\n</div>',
        "solution_css": "body { font-family:sans-serif; padding:2rem; background:#1e1e2e; color:white; }\n#open-btn { padding:0.5rem 1rem; background:#6c63ff; color:white; border:none; border-radius:6px; cursor:pointer; }\n#palette { position:fixed; inset:0; background:rgba(0,0,0,0.6); display:flex; align-items:flex-start; justify-content:center; padding-top:15vh; z-index:1000; }\n#palette.hidden { display:none; }\n.palette-inner { background:#2a2a3d; border-radius:12px; width:500px; overflow:hidden; box-shadow:0 20px 60px rgba(0,0,0,0.5); }\n#palette-search { width:100%; padding:16px 20px; background:transparent; border:none; border-bottom:1px solid #3a3a50; color:white; font-size:1rem; outline:none; box-sizing:border-box; }\n#cmd-list { list-style:none; padding:8px 0; margin:0; max-height:300px; overflow-y:auto; }\n.cmd-item { padding:10px 20px; cursor:pointer; color:#ccc; }\n.cmd-item:hover { background:#3a3a50; color:white; }",
        "solution_js": 'var palette = document.getElementById("palette");\nvar search = document.getElementById("palette-search");\nvar items = document.querySelectorAll(".cmd-item");\n\nfunction openPalette() {\n  palette.classList.remove("hidden");\n  search.value = "";\n  items.forEach(function(el) { el.style.display = ""; });\n  search.focus();\n}\nfunction closePalette() { palette.classList.add("hidden"); }\n\ndocument.getElementById("open-btn").addEventListener("click", openPalette);\ndocument.addEventListener("keydown", function(e) {\n  if (e.key === "Escape") closePalette();\n});\nsearch.addEventListener("input", function() {\n  var q = search.value.toLowerCase();\n  items.forEach(function(item) {\n    item.style.display = item.textContent.toLowerCase().includes(q) ? "" : "none";\n  });\n});',
        "test_cases": json.dumps([
            {"type": "has_class", "selector": "#palette", "className": "hidden", "description": "Palette starts hidden"},
            {"type": "element_count", "selector": ".cmd-item", "expected": 5, "description": "Has 5 command items"},
            {"type": "event_test", "selector": "#open-btn", "event": "click", "then_check": {"type": "not_has_class", "selector": "#palette", "className": "hidden"}, "description": "Clicking button opens the palette"},
            {"type": "input_event_test", "selector": "#palette-search", "value": "git", "then_check": {"type": "visible_count", "selector": ".cmd-item", "expected": 1}, "description": "Typing 'git' filters to 1 result (Git Commit)"},
            {"type": "input_event_test", "selector": "#palette-search", "value": "", "then_check": {"type": "visible_count", "selector": ".cmd-item", "expected": 5}, "description": "Clearing search shows all 5 commands"},
        ]),
        "hints": json.dumps([
            "Use palette.classList.remove('hidden') to open and classList.add('hidden') to close",
            "Listen for keydown on document and check e.key === 'Escape' to close the palette",
            "Filter commands the same way as live search: item.textContent.toLowerCase().includes(query)",
        ]),
    },

